1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_SIZE = 3;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const CURSED_SURCHARGE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	const LOYALTY_DISCOUNT = -0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT = -0.15;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
14	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
15	const FULL_REIMBURSEMENT_RATE = 1;
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const INSURANCE_VALUE: Record<string, number> = {
27	  sword: 1000,
28	  amulet: 600,
29	  staff: 800,
30	  potion: 400,
31	  rune: 250,
32	  moonstone: 250,
33	};
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
38	type Customer = { yearsWithMHPCO?: number; firstInsurance?: boolean };
39	type Damage = { itemType: string; amount: number };
40	type Incident = { cause: string; damages: Damage[] };
41	type QuoteStep = { op: "quote"; items: Item[] };
42	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
43	type Step = QuoteStep | ClaimStep;
44	type Scenario = { customer: Customer; steps: Step[] };
45	
46	type Policy = { items: Item[]; cap: number };
47	
48	const lookupByType = (table: Record<string, number>, type: string): number => {
49	  const value = table[type];
50	  if (value === undefined) throw new Error(`unknown item type: ${type}`);
51	  return value;
52	};
53	
54	const basePremiumFor = (type: string): number => lookupByType(BASE_PREMIUM, type);
55	
56	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
57	
58	const isMainItem = (item: Item): boolean => !isComponent(item);
59	
60	const groupByType = (items: Item[]): Map<string, number> =>
61	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
62	
63	const componentGroupPremium = (type: string, count: number): number =>
64	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
65	
66	const componentsPremium = (items: Item[]): number =>
67	  Array.from(groupByType(items.filter(isComponent)))
68	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
69	
70	const isHighlyEnchanted = (item: Item): boolean =>
71	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
72	
73	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
74	
75	const itemRateAdjustment = (item: Item): number =>
76	  rateWhen(item.cursed === true, CURSED_SURCHARGE) +
77	  rateWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);
78	
79	const itemPremium = (item: Item): number =>
80	  basePremiumFor(item.type) * (1 + itemRateAdjustment(item));
81	
82	type PremiumBreakdown = { base: number; withSurcharges: number };
83	
84	const addBreakdowns = (a: PremiumBreakdown, b: PremiumBreakdown): PremiumBreakdown => ({
85	  base: a.base + b.base,
86	  withSurcharges: a.withSurcharges + b.withSurcharges,
87	});
88	
89	const mainItemBreakdown = (item: Item): PremiumBreakdown => ({
90	  base: basePremiumFor(item.type),
91	  withSurcharges: itemPremium(item),
92	});
93	
94	const componentsBreakdown = (items: Item[]): PremiumBreakdown => {
95	  const total = componentsPremium(items);
96	  return { base: total, withSurcharges: total };
97	};
98	
99	const itemsBreakdown = (items: Item[]): PremiumBreakdown =>
100	  items
101	    .filter(isMainItem)
102	    .map(mainItemBreakdown)
103	    .reduce(addBreakdowns, componentsBreakdown(items));
104	
105	const isLongStanding = (customer: Customer): boolean =>
106	  (customer.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
107	
108	const policyRateAdjustment = (customer: Customer, isFollowUp: boolean): number =>
109	  rateWhen(customer.firstInsurance === true, FIRST_INSURANCE_SURCHARGE) +
110	  rateWhen(isLongStanding(customer), LOYALTY_DISCOUNT) +
111	  rateWhen(isFollowUp, FOLLOW_UP_DISCOUNT);
112	
113	const FLOATING_POINT_EPSILON = 1e-9;
114	
115	const roundUpInOurFavor = (amount: number): number =>
116	  Math.ceil(amount - FLOATING_POINT_EPSILON);
117	
118	const policyPremium = (customer: Customer, items: Item[], isFollowUp: boolean): number => {
119	  const { base, withSurcharges } = itemsBreakdown(items);
120	  return withSurcharges + base * policyRateAdjustment(customer, isFollowUp) + PROCESSING_FEE;
121	};
122	
123	const quoteResult = (customer: Customer, items: Item[], isFollowUp: boolean): { premium: number } => ({
124	  premium: roundUpInOurFavor(policyPremium(customer, items, isFollowUp)),
125	});
126	
127	const insuranceValueFor = (type: string): number => lookupByType(INSURANCE_VALUE, type);
128	
129	const policyInsuranceSum = (items: Item[]): number =>
130	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
131	
132	const reimbursementRate = (item: Item | undefined): number =>
133	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
134	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
135	    : FULL_REIMBURSEMENT_RATE;
136	
137	const findInsuredItem = (items: Item[], type: string): Item | undefined =>
138	  items.find((i) => i.type === type);
139	
140	const damagePayout = (damage: Damage, items: Item[]): number => {
141	  const item = findInsuredItem(items, damage.itemType);
142	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
143	};
144	
145	const totalRawPayout = (damages: Damage[], items: Item[]): number =>
146	  damages.reduce((sum, d) => sum + damagePayout(d, items), 0);
147	
148	const openPolicy = (items: Item[]): Policy => ({
149	  items,
150	  cap: policyInsuranceSum(items) * CAP_MULTIPLIER,
151	});
152	
153	const settleClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
154	  const payout = Math.min(totalRawPayout(incident.damages, policy.items), policy.cap);
155	  policy.cap -= payout;
156	  return { payout, remainingCap: policy.cap };
157	};
158	
159	type QuoteResult = { premium: number };
160	type ClaimResult = { payout: number; remainingCap: number };
161	type StepResult = QuoteResult | ClaimResult;
162	
163	const processStep = (customer: Customer, policies: Policy[]) =>
164	  (step: Step, stepIndex: number): StepResult => {
165	    if (step.op === "quote") {
166	      policies[stepIndex] = openPolicy(step.items);
167	      return quoteResult(customer, step.items, stepIndex > 0);
168	    }
169	    return settleClaim(policies[step.policy], step.incident);
170	  };
171	
172	export const runScenario = (input: unknown): { results: StepResult[] } => {
173	  const { customer, steps } = input as Scenario;
174	  const policies: Policy[] = [];
175	  return { results: steps.map(processStep(customer, policies)) };
176	};
